\chapter{Sheaves of $k$-modules: sheafification, Ext, and the structure sheaf as a sheaf of $k$-modules}
\label{chap:Cohomology_StructureSheafModuleK}

This chapter implements Phase~A step~5 of \texttt{STRATEGY.md}: equipping $H^1(C, \struct C)$ with a $k$-vector-space structure when $C$ is a scheme over $\Spec k$. The route is through Mathlib's general $\Linear k$ enrichment of $\Sheaf(\opens X, \ModuleCat k)$ together with \lstinline{CategoryTheory.Abelian.Ext.instModule}, which automatically provides $\Module k$ on $\Ext$ groups in any $\Linear k$ abelian category. The chapter introduces no protected declarations: every instance and definition here is auxiliary, supporting the construction of $H^1(C, \struct C)$ in Definition~\ref{def:genus}.

The chapter is split into two sections of work. Section~\ref{sec:moduleK_prereqs} and~\ref{sec:moduleK_ext} (the iteration~005 work) provide the typeclass plumbing — the $\HasSheafify$ and $\HasExt$ instances on $\Sheaf(\opens X, \ModuleCat k)$. Section~\ref{sec:scheme_toModuleKSheaf} (the iteration~006 work) provides the \emph{substantive} content of Phase~A step~5: the $\ModuleCat k$-valued structure sheaf $\toModuleKSheaf C$ for $C : \mathrm{Over}\,(\Spec k)$, viewing $\struct C$ as a sheaf of $k$-modules via the structure morphism. Together these complete Phase~A step~5; the final remaining piece for an honest definition of $\genus C$ as $\dim_k H^1(C, \struct C)$ is then Phase~A step~6 (Serre finiteness, multi-iteration).

A discovery probe of Mathlib \texttt{b80f227} (logged in \texttt{task\_pending.md}) confirms that the four typeclass pieces of Sections~\ref{sec:moduleK_prereqs}–\ref{sec:moduleK_ext} are already in Mathlib (no new mathematical content; only universe-pinned packaging) and that the eight pieces of Section~\ref{sec:scheme_toModuleKSheaf} type-check end-to-end (~80 LOC; one short proof per piece). After this chapter lands, the typeclass chain \[ \HasSheafify \to \HasExt \to \Linear k \to \mathtt{Ext.instModule} \] is in place and $\toModuleKSheaf C$ provides the actual carrier on which it operates; the $\Module k$ instance on $H^1(C, \struct C) := (\toModuleKSheaf C).\mathtt H\,1$ is then automatic.

\section{Sheafification of $\ModuleCat k$-valued sheaves on opens}
\label{sec:moduleK_prereqs}

\begin{theorem}[Sheafification on the topology of opens, $\ModuleCat k$-valued]
  \label{thm:HasSheafify_Opens_ModuleCatK}
  \lean{AlgebraicGeometry.Cohomology.instHasSheafify_Opens_ModuleCatK}
  \leanok
  Let $k$ be a commutative ring and $X$ a topological space. Then the Grothendieck topology of opens of $X$ has
  \[
    \mathtt{HasSheafify}(\opens(X), \ModuleCat\, k).
  \]
\end{theorem}

\begin{proof}
  \leanok
  Mathlib's general sheafification API constructs \lstinline{HasSheafify J A} whenever \lstinline{HasWeakSheafify J A} holds and the resulting sheafification preserves finite limits. For \lstinline{J = Opens.grothendieckTopology X} and \lstinline{A = ModuleCat k} both prerequisites are wired in Mathlib (small-site sheafification on a concrete category, plus exactness of $\ModuleCat k$-valued sheafification). The instance is therefore inferable; the prover's task is to reproduce the universe pinning that succeeded for the iter-004 $\AddCommGrpCat$ analogue (Theorem~\ref{thm:HasSheafify_Opens_AddCommGrp}).
\end{proof}

\section{$\Ext$ for $\ModuleCat k$-valued sheaves on opens}
\label{sec:moduleK_ext}

\begin{theorem}[$\Ext$ on the topology of opens, $\ModuleCat k$-valued]
  \label{thm:HasExt_Sheaf_Opens_ModuleCatK}
  \lean{AlgebraicGeometry.Cohomology.instHasExt_Sheaf_Opens_ModuleCatK}
  \uses{thm:HasSheafify_Opens_ModuleCatK}
  \leanok
  Let $k$ be a commutative ring and $X$ a topological space. Then the category $\Sheaf(\opens(X), \ModuleCat k)$ has
  \[
    \mathtt{HasExt.\{u+1\}}\bigl(\Sheaf(\opens(X), \ModuleCat k)\bigr).
  \]
\end{theorem}

\begin{proof}
  \uses{thm:HasSheafify_Opens_ModuleCatK}
  \leanok
  $\ModuleCat k$ is abelian. The sheaf category $\Sheaf(J, A)$ inherits an abelian structure from an abelian $A$ once \lstinline{HasSheafify J A} holds (Theorem~\ref{thm:HasSheafify_Opens_ModuleCatK}). Mathlib's \lstinline{CategoryTheory.HasExt.standard} produces a \lstinline{HasExt} instance from any abelian category. The universe annotation \lstinline{HasExt.\{u+1\}} matches the unique morphism universe of \lstinline{Sheaf (Opens.gT X) (ModuleCat.\{u\} k)}, mirroring the iter-004 $\AddCommGrpCat$ analogue (Theorem~\ref{thm:HasExt_Sheaf_Opens_AddCommGrp}).
\end{proof}

